// ─── GMAIL OAUTH ───────────────────────────────────────────────────────────────
function useGmail() {
  const [token, setToken] = useState(null);
  const [userEmail, setUserEmail] = useState(null);

  const login = useCallback(() => {
    const redirectUri = "https://darydaryy.github.io/jobradar-/";
    const params = new URLSearchParams({
      client_id: CLIENT_ID,
      redirect_uri: redirectUri,
      response_type: "token",
      scope: GMAIL_SCOPE,
      prompt: "consent",
    });
    window.location.href = `https://accounts.google.com/o/oauth2/auth?${params}`;
  }, []);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.includes("access_token")) {
      const params = new URLSearchParams(hash.replace("#", "?"));
      const t = params.get("access_token");
      if (t) {
        setToken(t);
        window.history.replaceState({}, "", window.location.pathname);
        // Fetch user email
        fetch("https://www.googleapis.com/oauth2/v2/userinfo", {
          headers: { Authorization: `Bearer ${t}` },
        })
          .then((r) => r.json())
          .then((d) => setUserEmail(d.email))
          .catch(() => {});
      }
    }
  }, []);

  const sendEmail = useCallback(
    async ({ to, subject, body, attachmentBase64, attachmentName, attachmentMime }) => {
      if (!token) throw new Error("Not authenticated");

      const boundary = "boundary_" + Math.random().toString(36).slice(2);
      const nl = "\r\n";

      let raw = [
        `To: ${to}`,
        `From: ${userEmail || "kalinina365975@gmail.com"}`,
        `Subject: =?utf-8?B?${btoa(unescape(encodeURIComponent(subject)))}?=`,
        `MIME-Version: 1.0`,
        `Content-Type: multipart/mixed; boundary="${boundary}"`,
        nl,
        `--${boundary}`,
        `Content-Type: text/plain; charset="utf-8"`,
        `Content-Transfer-Encoding: base64`,
        nl,
        btoa(unescape(encodeURIComponent(body))),
        nl,
      ];

      if (attachmentBase64 && attachmentName) {
        raw = raw.concat([
          `--${boundary}`,
          `Content-Type: ${attachmentMime || "application/pdf"}; name="${attachmentName}"`,
          `Content-Transfer-Encoding: base64`,
          `Content-Disposition: attachment; filename="${attachmentName}"`,
          nl,
          attachmentBase64,
          nl,
        ]);
      }

      raw.push(`--${boundary}--`);
      const message = raw.join(nl);
      const encoded = btoa(unescape(encodeURIComponent(message)))
        .replace(/\+/g, "-")
        .replace(/\//g, "_")
        .replace(/=+$/, "");

      const res = await fetch("https://gmail.googleapis.com/gmail/v1/users/me/messages/send", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ raw: encoded }),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error?.message || "Failed to send email");
      }
      return await res.json();
    },
    [token, userEmail]
  );

  return { token, userEmail, login, sendEmail };
}

// ─── AI FUNCTIONS ─────────────────────────────────────────────────────────────
async function searchJobsWithAI(signal) {
  const response = await fetch("https://jobradar-proxy.vercel.app/api/anthropic", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    signal,
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      tools: [{ type: "web_search_20250305", name: "web_search" }],
      system: `You are a job search assistant. Search for REAL current job openings for Product Manager and Project Manager positions at international (non-Russian) companies that accept remote workers or candidates from Armenia/CIS. Focus on companies that hire remotely from Eastern Europe. Return results as JSON only — no markdown, no explanation, just the raw JSON array.`,
      messages: [
        {
          role: "user",
          content: `Search for current job openings for "Product Manager remote" and "Project Manager remote" at international tech companies. Find real postings from 2025-2026. 

Return ONLY a JSON array (no markdown, no backticks) with 8-10 jobs:
[
  {
    "id": "unique_id",
    "company": "Company Name",
    "role": "Exact Role Title",
    "type": "product_manager" or "project_manager",
    "location": "Remote / City",
    "description": "2-3 sentences about the role and requirements",
    "email": "jobs@company.com or hr@company.com (best guess for HR email)",
    "url": "job posting URL if found",
    "matchScore": 85,
    "matchReason": "Why this matches Daria's profile in 1 sentence"
  }
]

Daria's profile: 4+ years PM, 9+ years tech, launched AI SaaS to 6000 users, worked at OZON/Zvuk/systeme.io, English B2/C1, Figma/Jira/SQL/Python, based in Yerevan Armenia, open to remote international roles.`,
        },
      ],
    }),
  });

  const data = await response.json();
  const text = data.content
    .map((b) => (b.type === "text" ? b.text : ""))
    .join("")
    .trim();

  // Try to extract JSON
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    return JSON.parse(jsonMatch[0]);
  }
  throw new Error("Could not parse jobs from AI response");
}

async function generateCoverLetter(job, resumeType) {
  const resumeSummary = resumeType === "product_manager" ? RESUME_PM_SUMMARY : RESUME_PJM_SUMMARY;
  const response = await fetch("https://jobradar-proxy.vercel.app/api/anthropic", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      messages: [
        {
          role: "user",
          content: `Write a professional cover letter email in English for this job application.

Candidate: ${resumeSummary}

Job: ${job.role} at ${job.company}
Description: ${job.description}

Write a concise, compelling cover letter (3-4 paragraphs). Start with "Dear Hiring Team," and end with contact info placeholder [CONTACT]. Make it personalized and highlight the most relevant experience. Output ONLY the email body text, no subject line.`,
        },
      ],
    }),
  });

  const data = await response.json();
  return data.content[0]?.text || "";
}

// ─── STORAGE ──────────────────────────────────────────────────────────────────
function useApplications() {
  const [applications, setApplications] = useState(() => {
    try {
      const stored = window.storage ? null : null; // use in-memory
      return [];
    } catch {
      return [];
    }
  });

  const addApplication = useCallback((app) => {
    setApplications((prev) => [app, ...prev]);
  }, []);

  const updateApplication = useCallback((id, updates) => {
    setApplications((prev) => prev.map((a) => (a.id === id ? { ...a, ...updates } : a)));
  }, []);

  return { applications, addApplication, updateApplication };
}

